import React, { useState } from 'react';
import DatePicker from 'react-datepicker';
import "react-datepicker/dist/react-datepicker.css";
import { Search } from 'lucide-react';

const SearchBar = ({ onSearch }) => {
    const [location, setLocation] = useState('');
    const [startDate, setStartDate] = useState(null);
    const [endDate, setEndDate] = useState(null);
    const [guests, setGuests] = useState(1);

    const handleSubmit = (e) => {
        e.preventDefault();
        onSearch({ location, startDate, endDate, guests });
    };

    return (
        <div className="bg-white rounded-full shadow-lg p-2 max-w-4xl mx-auto border border-gray-200 hover:shadow-xl transition-shadow duration-300">
            <form onSubmit={handleSubmit} className="flex flex-col md:flex-row items-center divide-y md:divide-y-0 md:divide-x divide-gray-200">

                <div className="px-6 py-2 w-full md:w-1/3 hover:bg-gray-50 rounded-full transition-colors cursor-pointer group">
                    <label className="block text-xs font-bold text-gray-800 uppercase tracking-wider group-hover:text-rose-500 transition-colors">Location</label>
                    <input
                        type="text"
                        placeholder="Where are you going?"
                        className="w-full bg-transparent border-none p-0 text-gray-600 placeholder-gray-400 focus:ring-0 text-sm truncate font-medium"
                        value={location}
                        onChange={(e) => setLocation(e.target.value)}
                    />
                </div>

                <div className="px-6 py-2 w-full md:w-1/4 hover:bg-gray-50 transition-colors cursor-pointer group">
                    <label className="block text-xs font-bold text-gray-800 uppercase tracking-wider group-hover:text-rose-500 transition-colors">Check in</label>
                    <DatePicker
                        selected={startDate}
                        onChange={(date) => setStartDate(date)}
                        selectsStart
                        startDate={startDate}
                        endDate={endDate}
                        minDate={new Date()}
                        placeholderText="Add dates"
                        className="w-full bg-transparent border-none p-0 text-gray-600 focus:ring-0 text-sm font-medium cursor-pointer"
                        dateFormat="dd MMM"
                    />
                </div>

                <div className="px-6 py-2 w-full md:w-1/4 hover:bg-gray-50 transition-colors cursor-pointer group">
                    <label className="block text-xs font-bold text-gray-800 uppercase tracking-wider group-hover:text-rose-500 transition-colors">Check out</label>
                    <DatePicker
                        selected={endDate}
                        onChange={(date) => setEndDate(date)}
                        selectsEnd
                        startDate={startDate}
                        endDate={endDate}
                        minDate={startDate}
                        placeholderText="Add dates"
                        className="w-full bg-transparent border-none p-0 text-gray-600 focus:ring-0 text-sm font-medium cursor-pointer"
                        dateFormat="dd MMM"
                    />
                </div>

                <div className="px-6 py-2 w-full md:w-1/6 flex items-center justify-between hover:bg-gray-50 rounded-r-full transition-colors group">
                    <div className="flex-1">
                        <label className="block text-xs font-bold text-gray-800 uppercase tracking-wider group-hover:text-rose-500 transition-colors">Guests</label>
                        <input
                            type="number"
                            min="1"
                            className="w-full bg-transparent border-none p-0 text-gray-600 focus:ring-0 text-sm font-medium"
                            value={guests}
                            onChange={(e) => setGuests(e.target.value)}
                        />
                    </div>
                    <button type="submit" className="bg-rose-500 hover:bg-rose-600 text-white p-3 rounded-full shadow-md transition-all transform hover:scale-110 ml-2">
                        <Search className="w-5 h-5" />
                    </button>
                </div>

            </form>
        </div>
    );
};

export default SearchBar;
